import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import {
  Box,
  Typography,
  Grid,
  Card,
  CardContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Button,
  Chip,
  Avatar,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Divider,
} from "@mui/material";
import DashboardIcon from "@mui/icons-material/Dashboard";
import LocalHospitalIcon from "@mui/icons-material/LocalHospital";
import PersonIcon from "@mui/icons-material/Person";
import CalendarMonthIcon from "@mui/icons-material/CalendarMonth";
import AddIcon from "@mui/icons-material/Add";

const getStatusChip = (status) => {
  const colors = { Scheduled: "warning", Completed: "success", Cancelled: "error" };
  return <Chip label={status || "Scheduled"} color={colors[status] || "default"} size="small" />;
};

const AdminDashboard = () => {
  const navigate = useNavigate();

  useEffect(() => {
    const isLoggedIn = localStorage.getItem("isAdminLoggedIn");
    if (isLoggedIn !== "true") navigate("/admin/login");
  }, [navigate]);

  const [activeTab, setActiveTab] = useState("dashboard");

  const [appointments, setAppointments] = useState(() => {
    return JSON.parse(localStorage.getItem("appointments")) || [];
  });

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem("appointments")) || [];
    setAppointments(saved);
  }, []);

  return (
    <Box sx={{ display: "flex", minHeight: "100vh", bgcolor: "#f5f5f5" }}>
      {/* Sidebar */}
      <Box sx={{ width: 280, bgcolor: "#1a3c5e", color: "white", p: 3 }}>
        <Typography variant="h5" sx={{ mb: 5, fontWeight: "bold", textAlign: "center" }}>
          Admin Dashboard
        </Typography>
        <List>
          {["dashboard", "hospitals", "doctors", "appointments"].map((tab) => (
            <ListItem
              button
              key={tab}
              sx={{ bgcolor: activeTab === tab ? "#2c5282" : "transparent", borderRadius: 1, mb: 1 }}
              onClick={() => setActiveTab(tab)}
            >
              <ListItemIcon sx={{ color: "white" }}>
                {tab === "dashboard" && <DashboardIcon />}
                {tab === "hospitals" && <LocalHospitalIcon />}
                {tab === "doctors" && <PersonIcon />}
                {tab === "appointments" && <CalendarMonthIcon />}
              </ListItemIcon>
              <ListItemText primary={tab.charAt(0).toUpperCase() + tab.slice(1)} />
            </ListItem>
          ))}
        </List>
      </Box>

      {/* Main Content */}
      <Box component="main" sx={{ flexGrow: 1, p: 5 }}>
        <Typography variant="h4" fontWeight="bold" gutterBottom sx={{ mb: 5 }}>
          {activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}
        </Typography>

        {/* Appointments Tab */}
        {activeTab === "appointments" && (
          <Paper elevation={3} sx={{ p: 5, borderRadius: 3 }}>
            <Typography variant="h5" fontWeight="bold" gutterBottom>
              Recent Appointments
            </Typography>
            <TableContainer sx={{ mt: 3 }}>
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell><strong>Patient Name</strong></TableCell>
                    <TableCell><strong>Doctor</strong></TableCell>
                    <TableCell><strong>Hospital</strong></TableCell>
                    <TableCell><strong>Preferred Time</strong></TableCell>
                    <TableCell><strong>Date</strong></TableCell>
                    <TableCell><strong>Status</strong></TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {appointments.length > 0 ? (
                    appointments.map((appt, i) => (
                      <TableRow key={i} hover>
                        <TableCell>{appt.patientName || "—"}</TableCell>
                        <TableCell>{appt.doctorName || "—"}</TableCell>
                        <TableCell>{appt.hospitalName || "—"}</TableCell>
                        <TableCell><strong>{appt.preferredTime || "—"}</strong></TableCell>
                        <TableCell>{appt.date || "—"}</TableCell>
                        <TableCell>{getStatusChip(appt.status)}</TableCell>
                      </TableRow>
                    ))
                  ) : (
                    <TableRow>
                      <TableCell colSpan={6} align="center">
                        <Typography color="text.secondary" sx={{ py: 8 }}>
                          No appointments booked yet
                        </Typography>
                      </TableCell>
                    </TableRow>
                  )}
                </TableBody>
              </Table>
            </TableContainer>
          </Paper>
        )}
      </Box>
    </Box>
  );
};

export default AdminDashboard;
